@Service
class RedirectUriValidator {

    /**
     * Validates redirect_uri using EXACT MATCH against registered URIs.
     * This is the ONLY secure way to validate redirect URIs per RFC 6749.
     *
     * We do NOT allow:
     * - Prefix matching (vulnerable to path traversal)
     * - Subdomain wildcards (vulnerable to subdomain takeover)
     * - Dynamic paths (vulnerable to open redirect)
     */
    public boolean isValidRedirectUri(RegisteredClient client, String redirectUri) {
        if (redirectUri == null || redirectUri.isBlank()) {
            return false;
        }

        // Parse and normalize the URI
        URI parsed;
        try {
            parsed = new URI(redirectUri);
        } catch (URISyntaxException e) {
            return false;
        }

        // Reject non-HTTPS URIs (except localhost for development)
        if (!"https".equalsIgnoreCase(parsed.getScheme())) {
            if (!isLocalhostDevelopment(parsed)) {
                return false;
            }
        }

        // Reject URIs with fragments (per RFC 6749 Section 3.1.2)
        if (parsed.getFragment() != null) {
            return false;
        }

        // Reject URIs with user info (e.g., https://legit.com@evil.com)
        if (parsed.getUserInfo() != null) {
            return false;
        }

        // EXACT MATCH against registered redirect URIs (normalized)
        String normalizedInput = normalizeUri(parsed);
        for (String registeredUri : client.getAllowedRedirectUris()) {
            try {
                String normalizedRegistered = normalizeUri(new URI(registeredUri));
                if (normalizedRegistered.equals(normalizedInput)) {
                    return true;
                }
            } catch (URISyntaxException e) {
                // Skip malformed registered URIs
            }
        }

        return false;
    }

    private String normalizeUri(URI uri) {
        // Normalize: lowercase scheme and host, remove default ports, remove trailing slash
        String scheme = uri.getScheme() != null ? uri.getScheme().toLowerCase() : "";
        String host = uri.getHost() != null ? uri.getHost().toLowerCase() : "";
        int port = uri.getPort();

        // Remove default ports
        if (("https".equals(scheme) && port == 443) || ("http".equals(scheme) && port == 80)) {
            port = -1;
        }

        String path = uri.getPath() != null ? uri.getPath() : "/";
        if (path.endsWith("/") && path.length() > 1) {
            path = path.substring(0, path.length() - 1);
        }

        String query = uri.getQuery() != null ? "?" + uri.getQuery() : "";

        String portStr = port > 0 ? ":" + port : "";
        return scheme + "://" + host + portStr + path + query;
    }

    private boolean isLocalhostDevelopment(URI uri) {
        String host = uri.getHost();
        return "http".equalsIgnoreCase(uri.getScheme()) &&
                (host != null && (host.equals("localhost") || host.equals("127.0.0.1")));
    }
}

// --- Authorization Code Store ---

@Service
class AuthorizationCodeStore {
    private static final int CODE_EXPIRATION_MINUTES = 10;
    private static final int CODE_LENGTH_BYTES = 32;

    private final Map<String, AuthorizationCode> codes = new ConcurrentHashMap<>();
    private final SecureRandom secureRandom = new SecureRandom();

    public AuthorizationCode generateCode(String clientId, String redirectUri, String scope) {
        cleanupExpiredCodes();

        String code = generateSecureCode();
        Instant expiresAt = Instant.now().plusSeconds(CODE_EXPIRATION_MINUTES * 60L);

        AuthorizationCode authCode = new AuthorizationCode(code, clientId, redirectUri, scope, expiresAt);
        codes.put(code, authCode);
        return authCode;
    }

    public Optional<AuthorizationCode> consumeCode(String code) {
        AuthorizationCode authCode = codes.get(code);
        if (authCode == null) {
            return Optional.empty();
        }

        // Remove immediately to prevent replay
        codes.remove(code);

        if (authCode.isExpired() || authCode.isUsed()) {
            return Optional.empty();
        }

        authCode.markUsed();
        return Optional.of(authCode);
    }

    private String generateSecureCode() {
        byte[] bytes = new byte[CODE_LENGTH_BYTES];
        secureRandom.nextBytes(bytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);
    }

    private void cleanupExpiredCodes() {
        codes.entrySet().removeIf(entry -> entry.getValue().isExpired());
    }
}

