    @GetMapping("/oauth/authorize")
    public ResponseEntity<?> authorize(
            @RequestParam(value = "response_type", required = false) String responseType,
            @RequestParam(value = "client_id", required = false) String clientId,
            @RequestParam(value = "redirect_uri", required = false) String redirectUri,
            @RequestParam(value = "scope", required = false, defaultValue = "read") String scope,
            @RequestParam(value = "state", required = false) String state) {

        // Validate response_type
        if (!"code".equals(responseType)) {
            return ResponseEntity.badRequest().body(
                    new OAuthErrorResponse("unsupported_response_type",
                            "Only 'code' response type is supported"));
        }

        // Validate client_id
        if (clientId == null || clientId.isBlank()) {
            return ResponseEntity.badRequest().body(
                    new OAuthErrorResponse("invalid_request", "client_id is required"));
        }

        Optional<RegisteredClient> clientOpt = clientRegistry.findByClientId(clientId);
        if (clientOpt.isEmpty()) {
            return ResponseEntity.badRequest().body(
                    new OAuthErrorResponse("invalid_client", "Unknown client_id"));
        }

        RegisteredClient client = clientOpt.get();

        // Validate redirect_uri - STRICT EXACT MATCH
        if (redirectUri == null || redirectUri.isBlank()) {
            return ResponseEntity.badRequest().body(
                    new OAuthErrorResponse("invalid_request", "redirect_uri is required"));
        }

        if (!redirectUriValidator.isValidRedirectUri(client, redirectUri)) {
            // Per RFC 6749 Section 4.1.2.1: Do NOT redirect to an invalid redirect_uri
            // Display the error directly to the user instead
            return ResponseEntity.badRequest().body(
                    new OAuthErrorResponse("invalid_request",
                            "redirect_uri does not match any registered redirect URI for this client"));
        }

        // State parameter is recommended (warn if missing but don't reject)
        // In production, you'd show a consent page here

        // Generate authorization code
        AuthorizationCode authCode = codeStore.generateCode(clientId, redirectUri, scope);

        // Build redirect response
        String redirectLocation = buildRedirectUrl(redirectUri, authCode.getCode(), state);

        return ResponseEntity.status(HttpStatus.FOUND)
                .header("Location", redirectLocation)
                .header("Cache-Control", "no-store")
                .header("Pragma", "no-cache")
                .build();
    }

    @PostMapping("/oauth/token")
    public ResponseEntity<?> token(
            @RequestParam(value = "grant_type", required = false) String grantType,
            @RequestParam(value = "code", required = false) String code,
            @RequestParam(value = "redirect_uri", required = false) String redirectUri,
            @RequestParam(value = "client_id", required = false) String clientId,
            @RequestParam(value = "client_secret", required = false) String clientSecret) {

        if (!"authorization_code".equals(grantType)) {
            return ResponseEntity.badRequest().body(
                    new OAuthErrorResponse("unsupported_grant_type",
                            "Only 'authorization_code' grant type is supported"));
        }

        if (code == null || code.isBlank()) {
            return ResponseEntity.badRequest().body(
                    new OAuthErrorResponse("invalid_request", "code is required"));
        }

        // Validate client credentials
        Optional<RegisteredClient> clientOpt = clientRegistry.findByClientId(clientId);
        if (clientOpt.isEmpty() || !clientOpt.get().getClientSecret().equals(clientSecret)) {
            return ResponseEntity.status(HttpStatus.UNAUTHORIZED).body(
                    new OAuthErrorResponse("invalid_client", "Invalid client credentials"));
        }

        // Consume authorization code
        Optional<AuthorizationCode> authCodeOpt = codeStore.consumeCode(code);
        if (authCodeOpt.isEmpty()) {
            return ResponseEntity.badRequest().body(
                    new OAuthErrorResponse("invalid_grant", "Invalid or expired authorization code"));
        }

        AuthorizationCode authCode = authCodeOpt.get();

        // Verify the code was issued to this client
        if (!authCode.getClientId().equals(clientId)) {
            return ResponseEntity.badRequest().body(
                    new OAuthErrorResponse("invalid_grant", "Code was not issued to this client"));
        }

        // Verify redirect_uri matches the one used during authorization
        if (!authCode.getRedirectUri().equals(redirectUri)) {
            return ResponseEntity.badRequest().body(
                    new OAuthErrorResponse("invalid_grant", "redirect_uri mismatch"));
        }

        // Generate token response (simplified)
        Map<String, Object> tokenResponse = new HashMap<>();
        tokenResponse.put("access_token", UUID.randomUUID().toString());
        tokenResponse.put("token_type", "Bearer");
        tokenResponse.put("expires_in", 3600);
        tokenResponse.put("scope", authCode.getScope());

        return ResponseEntity.ok()
                .header("Cache-Control", "no-store")
                .header("Pragma", "no-cache")
                .body(tokenResponse);
    }

    private String buildRedirectUrl(String redirectUri, String code, String state) {
        StringBuilder sb = new StringBuilder(redirectUri);
        sb.append(redirectUri.contains("?") ? "&" : "?");
        sb.append("code=").append(code);
        if (state != null && !state.isBlank()) {
            sb.append("&state=").append(state);
        }
        return sb.toString();
    }
